#include <stdio.h>

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char type[101], name[101], color[101];
        int n;
        scanf("%s", type);
        scanf("%s", name);
        scanf("%s", color);
        scanf("%d", &n);
        printf("Your dream pet is a %s %s named %s.\n", color, type, name);
        printf("You dream of having %d %s(s), but imagine having %d! How adorable!", n, type, n+1);
        if(T) printf("\n");
    }
    return 0;
}

