import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for(int tc=0; tc<T; tc++){
            String type = br.readLine().trim();
            String name = br.readLine().trim();
            String color = br.readLine().trim();
            int n = Integer.parseInt(br.readLine().trim());
            out.append("Your dream pet is a ").append(color).append(' ').append(type).append(" named ").append(name).append('.').append('\n');
            out.append("You dream of having ").append(n).append(' ').append(type).append("(s), but imagine having ").append(n+1).append("! How adorable!");
            if(tc != T-1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

