const T = parseInt(lines[idx++].trim(), 10);
let output = [];
for(let tc = 0; tc < T; tc++){
  const type = lines[idx++].trim();
  const name = lines[idx++].trim();
  const color = lines[idx++].trim();
  const n = parseInt(lines[idx++].trim(), 10);
